package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreEmptyLines_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true);
        assertTrue(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_WithIgnoreEmptyLinesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_Excel() {
        // EXCEL is defined as DEFAULT.withIgnoreEmptyLines(false).withAllowMissingColumnNames();
        CSVFormat format = CSVFormat.EXCEL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_MySQL() {
        // MYSQL is defined as DEFAULT.withIgnoreEmptyLines(false)
        CSVFormat format = CSVFormat.MYSQL;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_RFC4180() {
        // RFC4180 is DEFAULT.withIgnoreEmptyLines(false)
        CSVFormat format = CSVFormat.RFC4180;
        assertFalse(format.getIgnoreEmptyLines());
    }

    @Test
    void testGetIgnoreEmptyLines_TDF() {
        // TDF is DEFAULT.withDelimiter(TAB).withIgnoreSurroundingSpaces();
        // It does not override ignoreEmptyLines, so should be same as DEFAULT
        CSVFormat format = CSVFormat.TDF;
        assertTrue(format.getIgnoreEmptyLines());
    }
}
